  end

  @type t :: %__MODULE__{
          bid: [Longbridge.Quote.V1.Depth.t()],
          ask: [Longbridge.Quote.V1.Depth.t()],
          sequence: integer(),
          symbol: String.t(),
          __uf__: [{non_neg_integer(), Protox.Types.tag(), binary()}]
        }
