      def encode!(msg) do
        {_acc = [], _acc_size = 0}
        |> encode_bid(msg)
        |> encode_ask(msg)
        |> encode_sequence(msg)
        |> encode_symbol(msg)
        |> encode_unknown_fields(msg)
      end
    )

    defp encode_bid({acc, acc_size}, msg) do
